class Solution:
    def maxScoreIndices(self, nums: List[int]) -> List[int]:
        n = len(nums)
        total_ones = sum(nums)
        max_score = 0
        best = []
        zeros = 0

        for i in range(n + 1):
            if i == 0:
                score = total_ones
            else:
                if nums[i - 1] == 0:
                    zeros += 1
                score = zeros + (total_ones - (i - zeros))

            if score > max_score:
                max_score = score
                best = [i]
            elif score == max_score:
                best.append(i)

        return best

